# BAD: business logic in view, request.user passed to service
def post(self, request):
    item_code = request.data.get("item_code")
    if not item_code:
        return Response({"error": "required"}, status=400)
    item = Item.objects.filter(code=item_code).first()
    if not item:
        raise Http404
    item.activated_by = request.user
    item.save()
    return Response({"status": "ok"})
